#include <stdio.h>
#define M 1000000007
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    while (Q--) {
        int type, x, y, v;
        scanf("%d %d %d", &type, &x, &y);
        x--; y--;
        if (type == 1) {
            scanf("%d", &v);
            for (int i = x; i <= y; i++) {
                A[i] = (A[i] + v) % M;
            }
        } else if (type == 2) {
            scanf("%d", &v);
            for (int i = x; i <= y; i++) {
                A[i] = (A[i] * v) % M;
            }
        } else if (type == 3) {
            scanf("%d", &v);
            for (int i = x; i <= y; i++) {
                A[i] = v;
            }
        } else {
            int sum = 0;
            for (int i = x; i <= y; i++) {
                sum = (sum + A[i]) % M;
            }
            printf("%d\n", sum);
        }
    }
    return 0;
}

